// API endpoint: POST /api/automated-protocol-optimization/experiments/[id]/analyze
// Story 9.3: Automated protocol optimization - Analyze experiment results
// Generated by: VoidBeast V4.0

import { type NextRequest, NextResponse } from 'next/server';
import { AutomatedProtocolOptimizationService } from '../../../../../lib/services/automated-protocol-optimization';

const service = new AutomatedProtocolOptimizationService();

// POST: Analyze experiment results
export async function POST(
  _request: NextRequest,
  { params }: { params: { id: string } },
) {
  try {
    const { id } = params;

    if (!id) {
      return NextResponse.json(
        { success: false, error: 'Experiment ID is required' },
        { status: 400 },
      );
    }

    const experimentResults = await service.analyzeExperimentResults(id);

    return NextResponse.json({
      success: true,
      data: experimentResults,
      message: 'Experiment analysis completed successfully',
    });
  } catch (error) {
    return NextResponse.json(
      {
        success: false,
        error: 'Failed to analyze experiment results',
        details: error instanceof Error ? error.message : 'Unknown error',
      },
      { status: 500 },
    );
  }
}
